# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import time
from umqtt.simple import MQTTClient

# Configuration
CLIENT_ID = 'esp32_sensor'
BROKER_IP = 'mqtt.example.com'  # Replace with your broker IP or domain
TOPIC_TEMP = b'sensors/temp'

# Initialize temperature sensor (example using DS18B20)
sensor = machine.ADC(machine.Pin(4))  # Adjust pin number as needed

def read_temperature():
    # Example function to read temperature from a sensor
    # Replace with actual sensor reading code
    return sensor.read() / 10.0  # Assuming the sensor returns a value in tenths of degrees Celsius

# Setup MQTT client
client = MQTTClient(CLIENT_ID, BROKER_IP)

try:
    client.connect()
    print('Connected to MQTT broker')

    while True:
        temp = read_temperature()
        message = str(temp).encode()
        client.publish(TOPIC_TEMP, message)
        print(f'Published temperature: {temp} C')
        
        time.sleep(60)  # Publish every minute

except Exception as e:
    print('Error:', e)

finally:
    client.disconnect()
    print('Disconnected from MQTT broker')